from flask import Flask, request, jsonify
from collections import defaultdict
import numpy as np
import json

app = Flask(__name__)

# In-memory storage for labels
labels = defaultdict(list)

@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data.get('image_id')
    label = data.get('label')
    if not image_id or label is None:
        return jsonify({'error': 'Invalid input'}), 400
    
    labels[image_id].append(label)
    return jsonify({'message': 'Label received'}), 200

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    
    for image_id, label_list in labels.items():
        if label_list:
            most_common_label = max(set(label_list), key=label_list.count)
            aggregated_labels[image_id] = most_common_label
    
    return jsonify(aggregated_labels), 200

